package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import java.io.IOException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setup() {
        csvFormat = new CSVFormat(',', '"', null, null, null, false, true, "\r\n", null, null, false, false);
    }

    @Test
    public void testGetQuoteCharacter() {
        // Given
        char expectedQuoteChar = '"';
        CSVFormat csvFormatMock = mock(CSVFormat.class);
        when(csvFormatMock.getQuoteCharacter()).thenReturn(expectedQuoteChar);

        // When
        char actualQuoteChar = csvFormatMock.getQuoteCharacter();

        // Then
        assertEquals(expectedQuoteChar, actualQuoteChar);
    }
}
